created=0
for slug, country in C.items():
    iso=country["iso"]
    visa_slug=country.get("visa_slug","")
    for lang in ["en","fr","es","pt"]:
        d=country[lang]
        out=os.path.join(WWW,lang,f"{slug}.html")
        html=page(lang,slug,iso,d,visa_slug)
        with open(out,"w",encoding="utf-8") as f:
            f.write(html)
        created+=1
        print(f"Created: {lang}/{slug}.html")

print(f"\nTotal: {created}")
